/**
 * Measures native property-path BFS over value ids against the generic PathIteration. The graph is a layered DAG (nodes
 * reachable through many redundant routes, so set semantics and visited-dedup matter). Run twice — once as-is and once
 * with {@code -Drdf4j.lmdb.nativePath.enabled=false}. The expected result counts are computed once at setup with the
 * native engine disabled (the generic evaluator is the semantics oracle), and every invocation verifies against them.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class PropertyPathReachabilityBenchmark {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final int LAYERS = 6;
	private static final int WIDTH = 5_000;
	private static final int FANOUT = 4;

	@Param({
			"selectReachable",
			"countReachable",
			"reverseReachable"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expectedRows;

	@Setup(Level.Trial)
	public void setUp() {
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p = vf.createIRI(EX, "p");
			conn.begin();
			for (int layer = 0; layer < LAYERS - 1; layer++) {
				for (int i = 0; i < WIDTH; i++) {
					IRI from = vf.createIRI(EX, "n" + layer + "_" + i);
					for (int j = 0; j < FANOUT; j++) {
						int child = (int) ((i * (long) FANOUT + j * 131L) % WIDTH);
						conn.add(from, p, vf.createIRI(EX, "n" + (layer + 1) + "_" + child));
					}
				}
			}
			conn.commit();
		}
		switch (variant) {
		case "selectReachable":
			query = "PREFIX ex: <" + EX + ">\nSELECT ?o WHERE { ex:n0_0 ex:p+ ?o . }";
			break;
		case "countReachable":
			query = "PREFIX ex: <" + EX + ">\nSELECT (COUNT(?o) AS ?count) WHERE { ex:n0_0 ex:p+ ?o . }";
			break;
		case "reverseReachable":
			query = "PREFIX ex: <" + EX + ">\nSELECT ?s WHERE { ?s ex:p+ ex:n" + (LAYERS - 1) + "_0 . }";
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
		// the generic evaluator is the semantics oracle for the expected size
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, "false");
			expectedRows = runQuery();
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		repository.shutDown();
		FileUtil.deleteDir(dataDir);
	}

	long runQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.size();
		}
	}

	@Benchmark
	public long executeQuery() {
		long rows = runQuery();
		if (rows != expectedRows) {
			throw new IllegalStateException(variant + ": expected " + expectedRows + " rows but got " + rows);
		}
		return rows;
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("PropertyPathReachabilityBenchmark")
				.build();
		new Runner(opt).run();
	}
}
